def hash_password(password):
    """Simple password hashing (use bcrypt/argon2 in production)."""
    import hashlib
    salt = "fixed_salt_replace_with_per_user_salt"
    return hashlib.sha256(f"{salt}{password}".encode()).hexdigest()


def login_required(f):
    """Decorator to require login for web routes."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session or not session.get('authenticated'):
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


def api_key_required(f):
    """Decorator to require API key for API routes."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        api_key = request.headers.get('X-API-Key') or request.args.get('api_key')
        if not api_key or api_key not in API_KEYS:
            return jsonify({'error': 'Invalid or missing API key'}), 401
        request.api_user = API_KEYS[api_key]
        return f(*args, **kwargs)
    return decorated_function


