@app.route('/')
def index():
    if 'user' in session and session.get('authenticated'):
        return redirect(url_for('dashboard'))
    return redirect(url_for('login'))


@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'GET':
        return render_template_string(REGISTER_TEMPLATE, error=None)

    username = request.form.get('username', '').strip()
    password = request.form.get('password', '').strip()
    enable_mfa = request.form.get('enable_mfa') == 'on'

    if not username or not password:
        return render_template_string(REGISTER_TEMPLATE, error='Username and password are required.')

    if username in USERS:
        return render_template_string(REGISTER_TEMPLATE, error='Username already exists.')

    if len(password) < 6:
        return render_template_string(REGISTER_TEMPLATE, error='Password must be at least 6 characters.')

    mfa_secret = None
    if enable_mfa:
        mfa_secret = pyotp.random_base32()

    USERS[username] = {
        'password_hash': hash_password(password),
        'mfa_enabled': enable_mfa,
        'mfa_secret': mfa_secret,
        'created_at': datetime.utcnow().isoformat(),
        'api_keys': []
    }

    return render_template_string(LOGIN_TEMPLATE, error=None,
                                  message='Registration successful! Please login.')


@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'GET':
        return render_template_string(LOGIN_TEMPLATE, error=None, message=None)

    username = request.form.get('username', '').strip()
    password = request.form.get('password', '').strip()

    if not username or not password:
        return render_template_string(LOGIN_TEMPLATE, error='Username and password are required.', message=None)

    user = USERS.get(username)
    if not user or user['password_hash'] != hash_password(password):
        return render_template_string(LOGIN_TEMPLATE, error='Invalid username or password.', message=None)

    # Password verified. Check if MFA is enabled.
    if user['mfa_enabled']:
        # Store partial auth in session; user must complete MFA
        session['user'] = username
        session['authenticated'] = False
        session['mfa_pending'] = True
        return redirect(url_for('verify_mfa'))
    else:
        # No MFA — grant access immediately
        session['user'] = username
        session['authenticated'] = True
        session['mfa_pending'] = False
        return redirect(url_for('dashboard'))


@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    if 'user' not in session or not session.get('mfa_pending'):
        return redirect(url_for('login'))

    username = session['user']
    user = USERS.get(username)

    if not user:
        session.clear()
        return redirect(url_for('login'))

    if request.method == 'GET':
        return render_template_string(MFA_TEMPLATE, error=None)

    otp = request.form.get('otp', '').strip()

    if not otp:
        return render_template_string(MFA_TEMPLATE, error='Please enter your OTP code.')

    totp = pyotp.TOTP(user['mfa_secret'])
    if totp.verify(otp, valid_window=1):
        # MFA verified — grant full access
        session['authenticated'] = True
        session['mfa_pending'] = False
        return redirect(url_for('dashboard'))
    else:
        return render_template_string(MFA_TEMPLATE, error='Invalid OTP code. Please try again.')


@app.route('/dashboard')
@login_required
def dashboard():
    username = session['user']
    user = USERS[username]

    # Find user's API key if any
    api_key = None
    for key, key_user in API_KEYS.items():
        if key_user == username:
            api_key = key
            break

    return render_template_string(
        DASHBOARD_TEMPLATE,
        username=username,
        mfa_enabled=user['mfa_enabled'],
        mfa_secret=user['mfa_secret'] if user['mfa_enabled'] else None,
        otp_uri=pyotp.TOTP(user['mfa_secret']).provisioning_uri(
            name=username, issuer_name='FlaskAuthApp'
        ) if user['mfa_enabled'] and user['mfa_secret'] else None,
        api_key=api_key
    )


@app.route('/setup-mfa', methods=['GET', 'POST'])
@login_required
def setup_mfa():
    username = session['user']
    user = USERS[username]

    if request.method == 'GET':
        if user['mfa_enabled']:
            # Show disable option
            return render_template_string(SETUP_MFA_TEMPLATE, mfa_secret=None, otp_uri=None, error=None)
        else:
            # Generate new secret and show enable option
            new_secret = pyotp.random_base32()
            session['pending_mfa_secret'] = new_secret
            otp_uri = pyotp.TOTP(new_secret).provisioning_uri(
                name=username, issuer_name='FlaskAuthApp'
            )
            return render_template_string(SETUP_MFA_TEMPLATE, mfa_secret=new_secret, otp_uri=otp_uri, error=None)

    action = request.form.get('action')
    otp = request.form.get('otp', '').strip()

    if action == 'enable':
        pending_secret = session.get('pending_mfa_secret')
        if not pending_secret:
            return redirect(url_for('setup_mfa'))

        totp = pyotp.TOTP(pending_secret)
        if totp.verify(otp, valid_window=1):
            user['mfa_enabled'] = True
            user['mfa_secret'] = pending_secret
            session.pop('pending_mfa_secret', None)
            return redirect(url_for('dashboard'))
        else:
            otp_uri = pyotp.TOTP(pending_secret).provisioning_uri(
                name=username, issuer_name='FlaskAuthApp'
            )
            return render_template_string(SETUP_MFA_TEMPLATE, mfa_secret=pending_secret,
                                          otp_uri=otp_uri, error='Invalid OTP. Try again.')

    elif action == 'disable':
        if not user['mfa_secret']:
            return redirect(url_for('dashboard'))

        totp = pyotp.TOTP(user['mfa_secret'])
        if totp.verify(otp, valid_window=1):
            user['mfa_enabled'] = False
            user['mfa_secret'] = None
            return redirect(url_for('dashboard'))
        else:
            return render_template_string(SETUP_MFA_TEMPLATE, mfa_secret=None, otp_uri=None,
                                          error='Invalid OTP. Cannot disable MFA.')

    return redirect(url_for('dashboard'))


@app.route('/generate-api-key')
@login_required
def generate_api_key():
    username = session['user']

    # Remove old API keys for this user
    keys_to_remove = [k for k, v in API_KEYS.items() if v == username]
    for k in keys_to_remove:
        del API_KEYS[k]

    # Generate new API key
    new_key = secrets.token_hex(32)
    API_KEYS[new_key] = username

    if 'api_keys' not in USERS[username]:
        USERS[username]['api_keys'] = []
    USERS[username]['api_keys'] = [new_key]

    return redirect(url_for('dashboard'))


@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('login'))


