@app.route('/api/direct-login', methods=['POST'])
def api_direct_login():
    """
    Direct login endpoint for API clients and automated scripts.
    Authenticates with username/password and skips MFA entirely.
    Returns a session token / API key for subsequent requests.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body must be JSON'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '').strip()

    if not username or not password:
        return jsonify({'error': 'Username and password are required'}), 400

    user = USERS.get(username)
    if not user or user['password_hash'] != hash_password(password):
        return jsonify({'error': 'Invalid username or password'}), 401

    # Skip MFA — generate a session token for API usage
    session_token = secrets.token_hex(32)
    API_KEYS[session_token] = username

    return jsonify({
        'message': 'Login successful (MFA skipped for API access)',
        'username': username,
        'api_key': session_token,
        'mfa_enabled': user['mfa_enabled'],
        'note': 'Use the api_key in X-API-Key header for subsequent API requests'
    }), 200


@app.route('/api/profile', methods=['GET'])
@api_key_required
def api_profile():
    """Get user profile via API (no MFA required)."""
    username = request.api_user
    user = USERS.get(username)

    if not user:
        return jsonify({'error': 'User not found'}), 404

    return jsonify({
        'username': username,
        'mfa_enabled': user['mfa_enabled'],
        'created_at': user.get('created_at'),
    }), 200


